	.TITLE	TMIDI.ASM	.PROC	M680002	.RADIX	10.	.HEX;************************************************;*		TMIDI.ASM			*;************************************************;===== assemblage conditionnel ==============================;------------------------------------------------------------SM100	=	1	; Assemblage conditionnel SMAKY100. ;DEBUG	=	1	; Debug du programmeASSMILE	=	1	; Assemblage avec smile	.REF	SMAKY	.REF	SM100HARD	.REF	SHIDRIV100	.REF	BIOSDRIV	.REF	DRIVERS;***************************************************;; constante du driver; -------------------ADDTIME	=	H'105A		;adresse du pointeur sur sys_timeDIVFACT	=	D'118		;facteur de division NBMIN	=	13		;nombre min de byte LSTAMP	=	6		;longueur du stamp;ERTIMO	=	H'8111		; Erreur: TIME-OUT.;EROUTF	=	H'8511		; Erreur: OUT OF FILE.; CONTROL register 6850:MIDIMOD	=	B'00010110	;divise le clock par 64 				; 8 bits 1 stop bitBUSTINT=	B'00100000	; interrupt disable transmitERCVINT=	B'10000000	; interrupt disable receiveMASTRST	=	B'00000011	;soft reset; STATUS register 6850:OKJACK	=	2^BUSFUL!2^BUSRDY!2^BUSIREQ;BUSFUL	=	0		; Receive data full.;BUSRDY	=	1		; Transmit data empty.;BUSDCD	=	2		; Data carrier detect.;BUSCTS	=	3		; Clear to send.;BUSFERR	=	4		; Framing error.;BUSOERR	=	5		; Overrun error.;BUSPERR	=	6		; Parity error.;BUSIREQ	=	7		; Interrupt request.; VECTEUR D'INTERRUPTION usarts SM100:VECTINT	=	D'29		; Numro vecteur d'interrupt.ADVINT	=	4*VECTINT	; Adresse du vecteur d'interrupt.; ADRESSES ACIA 6850:MIDI1	=	ACIA0+2		; Usart 6850 no 1 DATA.SMIDI1	=	ACIA0		; Usart 6850 no 1 CONTROL-STATUS.MIDI2	=	ACIA1+2		; Usart 6850 no 2 DATA.SMIDI2	=	ACIA1		; Usart 6850 no 2 CONTROL-STATUS.;valeur par dfaut;-----------------	.LOC	0;=======================================================;; Variables du driver; -------------------LBNOTE	=	20000;variable de testeNUMDRIV:.BLKW	1	;numro du driverLNOTE	=	3BNOTE:	.BLKB	LBNOTE	;3 BYTE par note	.EVEN; var de synchroINDTIME:.BLKW	2	;contient le pointeur au systime lowPTRSEMA:.BLKW	2	;pointeur au smaphoreSVECT:	.BLKW	2	;sauve le vecteur d'interruptionRTEMPS:	.BLKW	2	;LSLtemps absolu de dpart (read)WTEMPS:	.BLKW	2	;LSLtemps absolu de dpart (write);var d'interruptionNBBYTE:	.BLKW	2	;nombre de byte  transfrerPTRBUF:	.BLKW	2	;pointeur au buffer de lectureLCOM:	.BLKW	1	;compteur de byte dernire commandeINTERR:	.BLKB	1	;flag d'erreur d'interruption.EVEN     ; var gnraleBREAD	=	0	; tat lectureBWRITE	=	1	; tat critureBABORT	=	2	; abort lecture et critureETAT:	.BLKB	1	; tat du driverLGVAR:	.LOC	0;//////////////////////////////////////////////////////////;///// programme principal ///////////////////////////////;//////////////////////////////////////////////////////////TMIDI:	CALL	INISYS	;initialise le systme	JUMP,NE	ERR	LIB	?AFTIM	.ASCIZ	"*****  Programme de test de MIDI <CR>"	.EVEN10$:	CALL	TEST2OUT:	CALL	OUTSYS.IF	ASSMILE	EXIT.ELSE	LIB	?CLOLIB	FOS	?STOP.ENDIF;//////////////////////////////////////////////////////;//////////////////////////////////////////////////////;-------\; INISYS >	prpare le porgramme;=======/;;;in :rien;out:A6 pointeur sur les var.;   :D7 si erreur;mod:FINISYS:	PUSHM.L	D1,D2,D4,A4.IF	ASSMILE.ELSE	LIB	?OPELIB.ENDIF	LOAD.W	D1,#MTYPCP	LOAD.L	D4,#LGVAR	GESMEM	?GETMEM		;prend la mmoire	JUMP,NE	90$	LOAD.L	A6,A4	DEC.L	D41$:	CLR.B	(A4+)		;vide le buffer	DECJ.W,NMO D4,1$	LOAD.L	A3,#R16"LMIDI	LOAD.L	A4,#R16"PMIDI	CLR.W	D3		;pour tous	FOS	?INSTALL	;install le driver	JUMP,NE	90$	LOAD.L	A3,#R16"NAMEDRIV	FOS	?UNAMDRIV	;D2 <-- numro de driver	JUMP,NE	90$	LOAD.W	(A6)+NUMDRIV,D2		LOAD.W	D4,#0			; smaphore de synchro	NTREL	?CRESEM	JUMP,NE	90$	LOAD.L	(A6)+PTRSEMA,A5	SETZ90$:	POPM.L	D1,D2,D4,A4	RETLMIDI:	.ASCIZ	"#MIDI:"NAMEDRIV:.ASCIZ	"MIDI_0"PMIDI:	.ASCIZ	"$MIDI_0"	.EVEN;-------\; OUTSYS >	sort du programme;=======/;;;in :rien;out:rien;mod:FOUTSYS:	PUSHM.L	D1,A4	LOAD.L	A3,#R16"LMIDI	CLR.W	D3	FOS	?DEINSTALL	;deinstall le driver midi	LOAD.L	A4,A6	LOAD.W	D1,#MTYPCP	GESMEM	?GIVMEM		;rend la mmoire	LOAD.L	A5,(A6)+PTRSEMA	NTREL	?KILLSEM		;tue le smaphore	POPM.L	D1,A4	RET;----\; ERR >		routine qui affiche une erreur;====/;;;in :D7 l'erreur;out:rienERR:	PUSH.W	D7	LIB	?AFCR	LOAD.W	D3,#AFINV	LIB	?AFCAR	POP.W	D7	LIB	?AFERROR	LOAD.B	D3,#AFDIR	LIB	?GETCAR	JUMP	OUT;//////////////////////////////////////////////////////////////;////Routine de bas niveau/////////////////////////////////////;//////////////////////////////////////////////////////////////;------\; TEST0 >	teste la mesure du temps;///////;;;in :rien;out:rien;mod:FTEST0:	PUSHM.L	D0,D3,D4,A4	LIB	?AFTIM	.ASCIZ	" Teste la dure H'100 * 20ms reponse = 100.<CR>"	.EVEN10$:	LOAD.L	A4,H'105A	ADD.L	A4,#2	LOAD.L	D0,(A4)	LOAD.L	D4,#H'100	;1000*20MS	NTREL	?DELMS	LOAD.L	D4,(A4)	SUB.L	D4,D0		;D4 * 50us 	DIV.WU	D4,#118	LIB	?AFX4	LIB	?AFSPACE	LIB	?GETCAR	COMP.B	D3,#END	JUMP,NE	10$	POPM.L	D0,D3,D4,A4	RET;------\; TEST1 >	crit une note sur l'interface MIDI;///////TEST1:	PUSHM.L	D3,D4,D5,A41$:	LIB	?AFTIM	.ASCIZ	"A"	.EVEN	LOAD.W	D2,(A6)+NUMDRIV	LOAD.L	A4,#R16"LISTE 	LOAD.L	D5,#ELISTE-LISTE	BIOS	?DWRITE	JUMP,NE	90$	LIB	?IFCAR	JUMP,NE	1$	COMP.B	D3,#END	JUMP,NE	1$	LIB	?AFTIM	.ASCIZ	"<CR>Fin du test."	.EVEN	SETZ90$:	POPM.L	D3,D4,D5,A4	RET;------\; TEST2 >	lit des notes du synth;///////;;;in :rien;out:rien;mod:FTEST2:	PUSHM.L	D0,D3,D4,D5,A0,A3,A5	LOAD.L	A0,#(A6)+BNOTE	LOAD.W	D0,#LBNOTE-111$:	CLR.B	(A0+)	DECJ.W,NMO D0,11$	NTREL	?GETPRIO				;D4 <-- priorit	LOAD.L	D5,#400	LOAD.L	A5,#R16"PROCRD	LOAD.L	A3,#R16"NPROCRD	NTREL	?CRETASK		;dmarre la lecture20$:;	LOAD.W	D4,#10;	NTREL	?DELMS	LIB	?GETCAR;	JUMP,NE 20$	COMP.W	D3,#END	JUMP,NE 20$	LOAD.W	D2,(A6)+NUMDRIV	BIOS	?DAVOTR		; avort la lecture	LOAD.W	D4,#50	NTREL	?DELMS	LOAD.L	D4,(A6)+NBBYTE	LIB	?AFX8	LIB	?AFSPACE	LOAD.W	D4,(A6)+INTERR	LIB	?AFX4	LIB	?AFCRJUMP 85$	LIB	?AFTIM	.ASCIZ	"<CR>Le buffer lu:<CR>"	.EVEN	LOAD.L	A4,#(A6)+BNOTE	LOAD.L	A3,A4	ADD.L	A3,(A6)+NBBYTE70$:	LOAD.B	D4,(A4+)	SL.W	D4,#8	LOAD.B	D4,(A4+)	TEST.W	D4	JUMP,EQ 75$	LOAD.W	D5,D472$:	LOAD.B	D4,(A4+)	LIB	?AFX2	DEC.W	D5	JUMP,NE 72$	LIB	?AFSPACE	JUMP	80$75$:	LIB	?AFTIM	.ASCIZ	"t="	.EVEN	LOAD.B	D4,(A4+)	SL.W	D4,#8	LOAD.B	D4,(A4+)	LIB	?AFX4	LIB	?AFSPACE80$:	COMP.L	A4,A3	JUMP,LO 70$85$:	LIB	?AFTIM	.ASCIZ	"<CR>(R)pte ? "	.EVEN	LIB	?GETCAR	COMP.B	D3,#'R	JUMP,NE 90$	LOAD.L	A4,#(A6)+BNOTE	LOAD.L	D5,(A6)+NBBYTE	LOAD.W	D2,(A6)+NUMDRIV	BIOS	?DWRITE	JUMP	85$90$:	POPM.L	D0,D3,D4,D5,A0,A3,A5	RETNPROCRD:	.ASCIZ	"PROCRD"	.EVENPROCRD:	LOAD.W	D2,(A6)+NUMDRIV	LOAD.L	A4,#(A6)+BNOTE	LOAD.L	D5,#LBNOTE	BIOS	?DREAD	LOAD.L	(A6)+NBBYTE,D5	; nombre de byte lu	LOAD.W	(A6)+INTERR,D7	NTREL	?ABORT;------\; TEST3 >	teste l'avort;///////;;;in :rien;out:rien;mod:FTEST3:	PUSHM.L	D0,D3,D4,D5,A0,A3,A5	NTREL	?GETPRIO				;D4 <-- priorit	LOAD.L	D5,#400	LOAD.L	A5,#R16"PROCRD	LOAD.L	A3,#R16"NPROCRD	NTREL	?CRETASK		;dmarre la lecture	LIB	?AFTIM	.ASCIZ	"<CR>Test l'abort: <AFINV>"	.EVEN	LOAD.W	D4,#20	NTREL	?DELMS	LOAD.L	A0,#(A6)+BNOTE		;vide le buffer de rception	LOAD.W	D0,#40-111$:	CLR.B	(A0+)	DECJ.W,NMO D0,11$	LOAD.W	D2,(A6)+NUMDRIV	BIOS	?DAVOTR		; avort la lecture	LOAD.L	A5,(A6)+PTRSEMA	NTREL	?WAITEV		;attent la fin	LOAD.W	D7,(A6)+INTERR	LIB	?AFERROR;ntrel	?wiatabdesc	pas dans smile	LIB	?AFTIM	.ASCIZ	"<CR><AFDIR>Le buffer lu:<CR>"	.EVEN	LOAD.W	D0,#18-1	LOAD.L	A4,#(A6)+BNOTE	LOAD.L	A0,#R16"NOTEON10$:	LOAD.B	D4,(A4+)		;affiche le buffer	LIB	?AFB8	LIB	?AFSPACE	LOAD.B	D4,(A0+)	LIB	?AFB8	LIB	?AFCR	DECJ.W,NMO D0,10$	LIB	?GETCAR	COMP.B	D3,#END	JUMP,EQ	90$	SETZ90$:	POPM.L	D0,D3,D4,D5,A0,A3,A5	RETP	=	B'10010000R	=	B'10000000LISTE:	.B	0,3	.B	P,60,64	.B	0,0	.B	0,10	.B	0,3	.B	R,60,64	.B	0,0	.B	0,10	.B	0,3	.B	P,61,64	.B	0,0	.B	0,10	.B	0,3	.B	R,61,64	.B	0,0	.B	0,10	.B	0,3	.B	P,62,64	.B	0,0	.B	0,10	.B	0,3	.B	R,62,64	.B	0,0	.B	0,10ELISTE:NOTEON:	.B	0	.B	0		;attention delay	.B	00	.B	100		;msNOTEON1:	.B	0	.B	3		;longueur de trois	.B	B'10010000	;canal 1	.B	D'60		;note C	.B	D'64		;vitesse moyenETEMPS:	.B	0	.B	0		;attention delay	.B	0	.B	2NOTEOFF:	.B	0	.B	3	.B	B'10000000	;canal 1	.B	D'60		;note C	.B	D'64		;vitesse moyen	ENDNOTE:	.END	TMIDI	